// Extract code and state from OAuth callback
const query = $input.first().json.query;

// Check for errors from Google
if (query.error) {
  throw new Error(`OAuth authorization failed: ${query.error}${query.error_description ? ' - ' + query.error_description : ''}`);
}

// Validate required parameters
if (!query.code) {
  throw new Error('Missing authorization code from Google');
}

if (!query.state) {
  throw new Error('Missing state parameter - potential CSRF attack');
}

return [{
  json: {
    code: query.code,
    restaurant_id: query.state
  }
}];

// Validate tokens from Google
const tokenResponse = $input.first().json;
const restaurant = $('Find Restaurant').item.json;

if (!tokenResponse.access_token) {
  throw new Error('Failed to receive access token from Google');
}

if (!tokenResponse.refresh_token) {
  throw new Error('Failed to receive refresh token.');
}

const expiresIn = tokenResponse.expires_in || 3600;
const expiryDate = new Date(Date.now() + (expiresIn * 1000));

// ⚠️ WARNING: Replace with proper AES-256 encryption
const encryptToken = (token) => {
  return `encrypted_base64:${Buffer.from(token).toString('base64')}`;
};

return [{
  json: {
    restaurant_airtable_id: restaurant.id,
    restaurant_id: restaurant.fields.restaurant_id,
    restaurant_name: restaurant.fields.restaurant_name,
    owner_email: restaurant.fields.owner_email,
    tier: restaurant.fields.tier,
    google_access_token_encrypted: encryptToken(tokenResponse.access_token),
    google_refresh_token_encrypted: encryptToken(tokenResponse.refresh_token),
    google_token_expires_at: expiryDate.toISOString(),
    access_token: tokenResponse.access_token,
    scope: tokenResponse.scope
  }
}];

// Extract Google Business Profile ID
const accountsResponse = $input.first().json;
const restaurantData = $('Prepare Token Data').item.json;

if (!accountsResponse.accounts || accountsResponse.accounts.length === 0) {
  throw new Error('No Google Business accounts found.');
}

const primaryAccount = accountsResponse.accounts[0];
const accountName = primaryAccount.name;
const accountId = accountName.split('/')[1];

return [{
  json: {
    ...restaurantData,
    google_business_profile_id: accountId,
    google_account_name: primaryAccount.accountName || 'Business Account'
  }
}];

