=<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial; text-align: center; padding: 50px; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); min-height: 100vh; margin: 0; }
    .container { background: white; padding: 50px; border-radius: 20px; box-shadow: 0 10px 40px rgba(0,0,0,0.2); max-width: 700px; margin: 0 auto; }
    h1 { color: #0d7377; font-size: 42px; }
    .warning { font-size: 60px; color: #ffa500; }
    .box { background: #fff3cd; padding: 25px; border-radius: 10px; margin: 25px 0; text-align: left; border-left: 4px solid #ffa500; }
    .box h3 { margin-top: 0; }
    .box ol { margin: 15px 0; }
    .code { background: #e9ecef; padding: 4px 10px; border-radius: 4px; font-family: monospace; }
    .button { display: inline-block; padding: 18px 40px; background: #0d7377; color: white; text-decoration: none; border-radius: 30px; font-weight: bold; margin: 20px 0; font-size: 18px; border: none; cursor: pointer; }
    .button:hover { background: #0a5a5c; }
    .button:disabled { background: #ccc; }
    #status { margin-top: 20px; padding: 15px; border-radius: 8px; font-weight: bold; }
  </style>
</head>
<body>
  <div class="container">
    <div class="warning">⏳</div>
    <h1>Almost There!</h1>
    <p><strong>{{ $('Extract Business Profile ID').item.json.restaurant_name }}</strong></p>

    <div class="box">
      <h3>Add Manager Access</h3>
      <ol>
        <li>Go to <a href="https://business.google.com" target="_blank">business.google.com</a></li>
        <li>Your business → Settings → Users</li>
        <li>Add: <span class="code">reviewai@YOUR-PROJECT.iam.gserviceaccount.com</span></li>
        <li>Role: <strong>Manager</strong></li>
        <li>Click Invite</li>
      </ol>
    </div>

    <button class="button" onclick="verify()" id="btn">✅ Verify Now</button>
    <div id="status"></div>

    <p style="font-size: 14px; margin-top: 30px;"><a href="http://YOUR_HELP_URL">Video tutorial</a></p>
  </div>

  <script>
  async function verify() {
    const btn = document.getElementById('btn');
    const status = document.getElementById('status');
    btn.disabled = true;
    btn.innerHTML = '🔄 Checking...';

    try {
      const res = await fetch('/webhook/verify-manager-access', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ restaurant_id: '{{ $('Extract Business Profile ID').item.json.restaurant_id }}' })
      });

      const data = await res.json();

      if (data.verified) {
        btn.innerHTML = '✅ Verified!';
        btn.style.background = '#28a745';
        status.innerHTML = '🎉 Success! Redirecting...';
        status.style.background = '#d4edda';
        setTimeout(() => window.location.href = 'http://YOUR_DASHBOARD_URL', 2000);
      } else {
        btn.innerHTML = '⚠️ Not Found - Try Again';
        btn.style.background = '#ffa500';
        btn.disabled = false;
        status.innerHTML = '⏳ Not detected. Make sure you added Manager role and wait 1-2 minutes.';
        status.style.background = '#fff3cd';
      }
    } catch (e) {
      btn.innerHTML = '❌ Error';
      btn.disabled = false;
      status.innerHTML = 'Error. Try again.';
    }
  }
  </script>
</body>
</html>
